#!/usr/bin/env bash
# ai-augmented-operation-unifi-unp.sh — AI-augmented operation (UniFi + unpoller + LLM agent stack) SOP walkthrough for UBNT/UniFi 企业 Wi-Fi 工程.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="UBNT/UniFi 企业 Wi-Fi 工程"
WORKFLOW="AI-augmented operation (UniFi + unpoller + LLM agent stack)"

usage() {
  cat <<EOF
ai-augmented-operation-unifi-unp.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./ai-augmented-operation-unifi-unp.sh             # interactive
  ./ai-augmented-operation-unifi-unp.sh --dry-run
  ./ai-augmented-operation-unifi-unp.sh --json
  ./ai-augmented-operation-unifi-unp.sh --explain
  ./ai-augmented-operation-unifi-unp.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "AI-augmented operation (UniFi + unpoller + LLM agent stack)" 工作流。

一句话: UBNT lacks Mist Marvis-style AIOps natively — assemble a "poor man's AIOps" stack with unpoller (metrics) + Grafana (visualization) + unifi-mcp (agent access) + Claude / LLM (analysis) (evidence: [T03-S017, T03-S026, T02 tools track])

入门 SOP 共 6 步, 失败模式自检 9 项。

相关心智模型:
  • 容量优先, 覆盖次之 (Capacity-first, coverage second): 80 人密集办公的 Wi-Fi 瓶颈不是覆盖, 是同信道干扰 (CCI) — 加 AP 反而让网络更慢; 工程师先算 airtime budget, 后摆 AP.
  • Retry rate > RSSI (重试率比信号强度更能定位问题): 客户跟你说 "信号差", 你先要 retry % 和 channel utilization, 不要 RSSI — RSSI 满格但 retry 30% (业内估计 — CCI 阈值) 是 CCI /

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Stand up unpoller**: Docker container scrapes UniFi controller API, writes to Prometheus or InfluxDB. Skip → no metrics history, can't do trend analysis."
  "**Stand up Grafana + dashboards**: import community dashboards from grafana.com (search \"unifi\"), customize for client count / retry % / AP CPU / channel utilization. Skip → metrics collected but no human-readable view."
  "**Define SLOs + alert rules**: e.g., \"no AP > 60% airtime > 5 min\" / \"no SSID failures > 1% over 10 min.\" Wire to Slack / email. Skip → metrics never trigger action, monitoring becomes wallpaper."
  "**Install unifi-mcp (or equivalent)**: MCP server exposes UniFi controller API to LLM agents (Claude, Cursor, etc.). Run in **read-only** mode initially. Skip → if no LLM integration, ops still 100% manual."
  "**Define agent runbooks**: \"if alert X fires, ask Claude to inspect APs A, B, C and recommend next action.\" Establish that Claude proposes, human approves. Skip → either no automation OR unsupervised LLM changes break things."
  "**Review cadence**: weekly look at dashboards + alert history + any Claude-proposed changes; monthly review SLOs (adjust thresholds based on real workload). Skip → setup decays; alerts go ignored; LLM context drifts."
)
declare -a FAILURE_MODES=(
  "**F1**: Build with Chroma in dev, then struggle migrating to Pinecone — wastes 1-2 weeks. (Generalized: build the whole stack with experimental MCP tools, then a UBNT API breaking change in Network 11.x silently breaks scraping; alerts go quiet, no one notices for 2 weeks.)"
  "**F2**: Wire Claude to write methods without review gate — agent \"fixes\" perceived issue by changing firewall rule at 3am, locks IT team out of own network."
  "**F3**: Set up dashboards, forget to set alerts — discover problems by user complaints anyway. Defeated the purpose."
  "**F4**: Forget single-maintainer risk on unifi-mcp / unifly — repo goes unmaintained, breaks at next UBNT API change, scramble to fork."
  "**Sources**:"
  "[Primary] unpoller GitHub (T03-S017)"
  "[Primary] CTS 385 Grafana dashboard episode (T03-S013)"
  "[Reference] Marvis / Mist comparison anchor (T03-S026)"
  "[Reference] Track 02 tools tier 3 (新兴)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "ai-augmented-operation-unifi-unp-walkthrough"
fi
